// Some portions generated by Codex
package org.eclipse.rdf4j.sail.memory;

import static org.assertj.core.api.Assertions.assertThat;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.eclipse.rdf4j.query.TupleQuery;
import org.eclipse.rdf4j.query.trace.QueryTrace;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.junit.jupiter.api.Test;

class QueryTraceMinusScopeExecutionTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final String MEDICAL = "http://example.com/theme/medical/";

	private static final IRI ENCOUNTER = VF.createIRI(MEDICAL, "Encounter");
	private static final IRI HAS_CONDITION = VF.createIRI(MEDICAL, "hasCondition");
	private static final IRI CODE = VF.createIRI(MEDICAL, "code");

	@Test
	void traceShouldMarkMinusAsNewScopeWhenRhsVariablesDoNotEscape() {
		SailRepository repository = new SailRepository(new MemoryStore());
		repository.init();

		try {
			addMedicalTraceData(repository);

			try (SailRepositoryConnection connection = repository.getConnection()) {
				TupleQuery query = connection.prepareTupleQuery(
						"PREFIX medical: <http://example.com/theme/medical/>\n"
								+ "SELECT * WHERE {\n"
								+ "  ?a a medical:Encounter.\n"
								+ "  MINUS { <urn:1> <urn:1> ?d. }\n"
								+ "  ?a medical:hasCondition ?d.\n"
								+ "  ?d medical:code ?code.\n"
								+ "} LIMIT 10");

				QueryTrace trace = query.trace();

				assertThat(trace.isSuccess()).isTrue();
				assertThat(trace.getLines())
						.extracting(QueryTrace.Line::getKind, QueryTrace.Line::getText)
						.contains(
								org.assertj.core.groups.Tuple.tuple("minus", "MINUS (new scope) {"),
								org.assertj.core.groups.Tuple.tuple("pattern",
										"<urn:1> <urn:1> ?d"),
								org.assertj.core.groups.Tuple.tuple("pattern",
										"?a <http://example.com/theme/medical/hasCondition> ?d"));
				String minusLineId = trace.getLines()
						.stream()
						.filter(line -> "minus".equals(line.getKind()))
						.map(QueryTrace.Line::getId)
						.findFirst()
						.orElseThrow();
				QueryTrace.Frame minusDecisionFrame = trace.getFrames()
						.stream()
						.filter(frame -> minusLineId.equals(frame.getLineId()))
						.filter(frame -> "match".equals(frame.getEvent()))
						.findFirst()
						.orElseThrow();
				assertThat(minusDecisionFrame.getInputBindings()).containsOnlyKeys("a");
				assertThat(minusDecisionFrame.getInputBindings()).doesNotContainKey("d");
				assertThat(trace.getFrames().get(trace.getFrames().size() - 1).getResultBindings())
						.containsEntry("d", "<urn:condition:1>")
						.containsEntry("code", "\"C1\"");
			}
		} finally {
			repository.shutDown();
		}
	}

	private static void addMedicalTraceData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			IRI encounter = VF.createIRI("urn:encounter:1");
			IRI condition = VF.createIRI("urn:condition:1");
			connection.add(encounter, RDF.TYPE, ENCOUNTER);
			connection.add(encounter, HAS_CONDITION, condition);
			connection.add(condition, CODE, VF.createLiteral("C1"));
			connection.add(VF.createIRI("urn:1"), VF.createIRI("urn:1"), VF.createIRI("urn:minus-local"));
			connection.commit();
		}
	}
}
